export function resetToLoggedOutHome(): void {
  const expired = 'Thu, 01 Jan 1970 00:00:00 GMT'
  for (const cookieName of CLIENT_AUTH_COOKIE_NAMES) {
    document.cookie = `${cookieName}=; expires=${expired}; path=/; SameSite=Lax`
  }
